                ? 'bg-teal-500/10 border-teal-500 shadow-[0_0_20px_rgba(20,184,166,0.3)]' 
                : 'bg-slate-900/40 border-slate-800 hover:border-slate-700 hover:bg-slate-800/50'
              } ${tile.id === 'notes' && isActive ? '!border-amber-500 !bg-amber-500/10 !shadow-[0_0_20px_rgba(245,158,11,0.3)]' : ''}`}
            >
              <div className={`mb-3 transition-transform group-hover:scale-110 ${isActive ? (tile.id === 'notes' ? 'text-amber-500' : 'text-teal-400') : 'text-slate-600'}`}>
                {tile.icon}
              </div>
              <span className={`text-[10px] font-black uppercase tracking-widest text-center leading-tight ${isActive ? (tile.id === 'notes' ? 'text-amber-500' : 'text-teal-400') : 'text-slate-500'}`}>
                {tile.label}
              </span>
            </button>
          );
        })}
      </div>

      <div className="animate-fade-in">
        {activeSubTab === 'summary' && (
          <SetupView 
            users={props.users}
            parts={props.parts}
            workplaces={props.workplaces}
            missingReasons={props.missingReasons}
            logisticsOperations={props.logisticsOperations || []}
            breakSchedules={props.breakSchedules}
            bomMap={props.bomMap}
            systemConfig={props.systemConfig}
          />
        )}
        {activeSubTab === 'users' && (
          <UserSection 
            users={props.users} 
            roles={props.roles} 
            onAddUser={props.onAddUser} 
            onUpdatePassword={props.onUpdatePassword} 
            onUpdateNickname={props.onUpdateNickname}
            onUpdateUserRole={props.onUpdateUserRole}
            onUpdateExportPermission={props.onUpdateExportPermission}
            onDeleteUser={props.onDeleteUser} 
          />
        )}
        {activeSubTab === 'parts' && (
          <PartsSection 
            parts={props.parts} 
            onAddPart={props.onAddPart} 
            onBatchAddParts={props.onBatchAddParts} 
            onDeletePart={props.onDeletePart} 
            onDeleteAllParts={props.onDeleteAllParts} 
          />
        )}
        {activeSubTab === 'wp' && (
          <WorkplaceSection 
            workplaces={props.workplaces} 
            logisticsOperations={props.logisticsOperations || []}
            onAddWorkplace={props.onAddWorkplace}
            onUpdateWorkplace={props.onUpdateWorkplace}
            onBatchAddWorkplaces={props.onBatchAddWorkplaces}
            onDeleteWorkplace={props.onDeleteWorkplace}
            onDeleteAllWorkplaces={props.onDeleteAllWorkplaces}
            onAddLogisticsOperation={props.onAddLogisticsOperation || (() => {})}
            onUpdateLogisticsOperation={props.onUpdateLogisticsOperation || (() => {})}
            onDeleteLogisticsOperation={props.onDeleteLogisticsOperation || (() => {})}
            onDeleteAllLogisticsOperations={props.onDeleteAllLogisticsOperations || (() => {})}
            mapSectors={mapSectors}
            onAddMapSector={props.onAddMapSector}
            onDeleteMapSector={id => props.onDeleteMapSector(id)}
            onUpdateMapSector={props.onUpdateMapSector}
            systemConfig={props.systemConfig}
            onUpdateSystemConfig={props.onUpdateSystemConfig}
          />
        )}
        {activeSubTab === 'bom' && (
          <BOMSection 
            bomMap={props.bomMap} 
            onAddBOMItem={props.onAddBOMItem} 
            onBatchAddBOMItems={props.onBatchAddBOMItems} 
            onDeleteBOMItem={props.onDeleteBOMItem} 
            onDeleteAllBOMItems={props.onDeleteAllBOMItems} 
          />
        )}
        {activeSubTab === 'system' && (
          <SystemSection 
            missingReasons={props.missingReasons} 
            breakSchedules={props.breakSchedules} 
            onAddMissingReason={props.onAddMissingReason} 
            onDeleteMissingReason={props.onDeleteMissingReason} 
            onAddBreakSchedule={props.onAddBreakSchedule} 
            onDeleteBreakSchedule={props.onDeleteBreakSchedule} 
            onUpdateAdminKey={props.onUpdateAdminKey}
            isAdminLockEnabled={props.systemConfig.adminLockEnabled || false}
            onToggleAdminLock={props.onToggleAdminLock}
            systemConfig={props.systemConfig}
            onUpdateSystemConfig={props.onUpdateSystemConfig}
          />
        )}
        {activeSubTab === 'maint' && (
          <MaintenanceSection 
            systemConfig={props.systemConfig} 
            onUpdateSystemConfig={props.onUpdateSystemConfig} 
            onArchiveTasks={props.onArchiveTasks} 
            onDailyClosing={props.onDailyClosing}
            onWeeklyClosing={props.onWeeklyClosing}
            onGetDocCount={props.onGetDocCount}
            onPurgeOldTasks={props.onPurgeOldTasks}
            onExportTasksJSON={props.onExportTasksJSON}
          />
        )}
        {activeSubTab === 'yearly' && (
          <YearlyClosing resolveName={resolveName} fetchSanons={props.fetchSanons} />
        )}
        {activeSubTab === 'notes' && props.currentUserRole === 'ADMIN' && (
          <AdminNotesSection 
            notes={props.adminNotes}
            onAddNote={props.onAddAdminNote}
            onDeleteNote={props.onDeleteAdminNote}
            onClearNotes={props.onClearAdminNotes}
            currentUser={props.currentUser}
            resolveName={resolveName}
          />
        )}
      </div>
    </div>
  );
};

export default SettingsTab;

import React, { useState, useMemo, useEffect, useCallback } from 'react';
import { createPortal } from 'react-dom';
import TaskList from './tabs/TaskList';
import SettingsTab from './settings/SettingsTab';
import AnalyticsTab from './tabs/Analytics/AnalyticsTab';
import MissingItemsTab from './tabs/MissingItemsTab';
import LogisticsCenterTab from './tabs/LogisticsCenterTab';
import InventoryTab from './tabs/InventoryTab';
import PermissionsTab from './tabs/PermissionsTab';
import BOMScreen from './tabs/BOMScreen';
import ProductionEntry from './tabs/ProductionEntry';
import PartCatalogTab from './tabs/PartCatalogTab';
import SectorPickerModal from './modals/SectorPickerModal';
import AppHeader from './AppHeader';
import TabNavigator from './TabNavigator';
import { UserData, DBItem, PartRequest, BreakSchedule, SystemBreak, BOMComponent, Role, Permission, Task, Notification as AppNotification, PriorityLevel, SystemConfig, MapSector, AdminNote } from '../types/appTypes';
import { useLanguage } from './LanguageContext';

declare var XLSX: any;

interface PartSearchScreenProps {
  currentUser: string;
  currentUserRole: 'ADMIN' | 'USER' | 'LEADER';
  onLogout: () => void;
  tasks: Task[];
  draftTasks: Task[];
  onAddTask: (partNumber: string, workplace: string | null, quantity: string | null, quantityUnit: string | null, priority: PriorityLevel, isLogistics?: boolean, note?: string, isProduction?: boolean, sourceSectorId?: string, targetSectorId?: string) => void; 
  onUpdateTask: (id: string, updates: Partial<Task>) => void;
  onToggleTask: (id: string) => void;
  onMarkAsIncorrect: (id: string) => void;
  onEditTask: (id: string, newText: string, newPriority?: PriorityLevel) => void;
  onDeleteTask: (id: string) => void;
  onToggleMissing: (id: string, reason?: string) => void; 
  onSetInProgress: (id: string) => void;
  onToggleBlock: (id: string) => void; 
  onToggleManualBlock: (id: string) => void;
  onExhaustSearch: (id: string) => void;
  onAddNote: (id: string, note: string) => void;
  onDeleteMissingItem: (id: string) => void;
  onDeleteMissingReason: (id: string) => void;
  onReleaseTask: (id: string) => void;
  onArchiveTasks: () => Promise<{ success: boolean; count?: number }>;
  onDailyClosing: () => Promise<{ success: boolean; count: number }>;
  onWeeklyClosing: () => Promise<{ success: boolean; count: number; sanon?: string }>;
  onFetchArchivedTasks: () => Promise<Task[]>;
  fetchSanons: () => Promise<any[]>;
  onStartAudit: (id: string) => void;
  onFinishAudit: (id: string, result: 'found' | 'missing', note: string) => void;
  onVerifyAdminPassword: (password: string) => boolean;
  onGetDocCount: () => Promise<number>;
  onPurgeOldTasks: () => Promise<number>;
  onExportTasksJSON: () => Promise<void>;
  users: UserData[];
  onAddUser: (user: UserData) => void;
  onUpdatePassword: (username: string, newPass: string) => void;
  onUpdateNickname: (username: string, newNick: string) => void;
  onUpdateUserRole: (username: string, newRole: any) => void;
  onDeleteUser: (username: string) => void;
  onUpdateExportPermission: (username: string, canExport: boolean) => void;
  parts: DBItem[];
  workplaces: DBItem[];
  missingReasons: DBItem[];
  onAddPart: (val: string, desc?: string) => void;
  onBatchAddParts: (vals: string[]) => void;
  onDeletePart: (val: string) => void;
  onDeleteAllParts: () => void;
  onAddWorkplace: (val: string, time?: number, x?: number, y?: number) => void;
  onUpdateWorkplace: (id: string, updates: Partial<DBItem>) => void;
  onBatchAddWorkplaces: (vals: string[]) => void;
  onDeleteWorkplace: (id: string) => void;
  onDeleteAllWorkplaces: () => void;
  onAddMissingReason: (val: string) => void;
  logisticsOperations: DBItem[];
  onAddLogisticsOperation: (val: string, time?: number, dist?: number) => void; 
  onUpdateLogisticsOperation: (id: string, updates: Partial<DBItem>) => void;
  onDeleteLogisticsOperation: (id: string) => void;
  mapSectors: MapSector[];
  onAddMapSector: (name: string, x: number, y: number, color?: string) => void;
  onDeleteMapSector: (id: string) => void;
  onUpdateMapSector: (id: string, updates: Partial<MapSector>) => void;
  partRequests: PartRequest[];
  onRequestPart: (part: string) => Promise<boolean>;
  onApprovePartRequest: (req: PartRequest) => void;
  onRejectPartRequest: (id: string) => void;
  breakSchedules: BreakSchedule[];
  systemBreaks: SystemBreak[];
  isBreakActive: boolean;
  onAddBreakSchedule: (start: string, end: string) => void;
  onDeleteBreakSchedule: (id: string) => void;
  bomMap: Record<string, BOMComponent[]>;
  bomRequests: any[];
  onAddBOMItem: (parent: string, child: string, qty: number) => void;
  onBatchAddBOMItems: (vals: string[]) => void;
  onDeleteBOMItem: (parent: string, child: string) => void;
  onDeleteAllBOMItems: () => void;
  onRequestBOM: (parent: string) => Promise<boolean>;
  onApproveBOMRequest: (req: any) => void;
  onRejectBOMRequest: (id: string) => void;
  roles: Role[];
  permissions: Permission[];
  onAddRole: (name: string) => void;
  onDeleteRole: (id: string) => void;
  onUpdatePermission: (permissionId: string, roleName: string, hasPermission: boolean) => void;
  notifications: AppNotification[];
  onClearNotification: (id: string) => void;
  installPrompt: any;
  onInstallApp: () => void;
  systemConfig: SystemConfig;
  onUpdateSystemConfig: (config: Partial<SystemConfig>) => void;
  dbLoadWarning: boolean;
  onUpdateAdminKey: (oldK: string, newK: string) => Promise<void>;
  onToggleAdminLock: (val: boolean) => void;
  settings?: any;
  // Admin Notes
  adminNotes: AdminNote[];
  onAddAdminNote: (text: string, author: string) => void;
  onDeleteAdminNote: (id: string) => void;
  onClearAdminNotes: () => void;
}

const PartSearchScreen: React.FC<PartSearchScreenProps> = (props) => {
  const { 
    currentUser, currentUserRole, onLogout, tasks, draftTasks, onAddTask, onUpdateTask, roles, permissions,
    notifications, onClearNotification, installPrompt, onInstallApp, parts, workplaces,
    onToggleTask, onEditTask, onDeleteTask, onToggleMissing, onSetInProgress, onToggleManualBlock, onExhaustSearch, onMarkAsIncorrect, onAddNote, onReleaseTask, missingReasons,
    users,
    onApprovePartRequest, onRejectPartRequest,
    onArchiveTasks, onDailyClosing, onWeeklyClosing, fetchSanons,
    breakSchedules,
    bomMap, bomRequests, onApproveBOMRequest, onRejectBOMRequest,
    onAddRole, onDeleteRole, onUpdatePermission, onVerifyAdminPassword,
    systemConfig, onUpdateSystemConfig,
    dbLoadWarning, onGetDocCount, onPurgeOldTasks, onExportTasksJSON,
    mapSectors, settings,
    adminNotes, onAddAdminNote, onDeleteAdminNote, onClearAdminNotes
  } = props;

  const { t, language, setLanguage } = useLanguage();
  const [activeTab, setActiveTab] = useState<'entry' | 'tasks' | 'settings' | 'analytics' | 'bom' | 'missing' | 'logistics' | 'permissions' | 'inventory' | 'catalog'>('entry');
  const [taskSearchQuery, setTaskSearchQuery] = useState('');
  const [entryMode, setEntryMode] = useState<'production' | 'logistics'>('production');

  // STAVY PRE SEKTOR PICKER
  const [pickingTask, setPickingTask] = useState<Task | null>(null);

  const [selectedPart, setSelectedPart] = useState<string | null>(null);
  const [selectedWorkplace, setSelectedWorkplace] = useState<string | null>(null);

  // Logistics States
  const [logisticsRef, setLogisticsRef] = useState('');
  const [logisticsOp, setLogisticsOp] = useState('');
  const [logisticsPlate, setLogisticsPlate] = useState('');
  const [sourceSector, setSourceSector] = useState<string | null>(null);
  const [targetSector, setTargetSector] = useState<string | null>(null);

  const [quantity, setQuantity] = useState<string>('');
  const [quantityUnit, setQuantityUnit] = useState<'pcs' | 'boxes' | 'pallet'>('pcs');
  const [priority, setPriority] = useState<PriorityLevel>('NORMAL');
  const [showSuccessMessage, setShowSuccessMessage] = useState(false);

  const unitLock = useMemo(() => {
    if (entryMode === 'logistics' || !selectedPart) return null;
    const partData = parts.find(p => p.value === selectedPart);
    const desc = partData?.description || '';
    if (desc.includes('S0001S')) return 'pcs';
    if (desc.includes('S0002S')) return 'boxes';
    if (desc.includes('S0003S')) return 'pallet';
    return null;
  }, [selectedPart, entryMode, parts]);

  useEffect(() => { if (unitLock) setQuantityUnit(unitLock); }, [unitLock]);

  const currentRoleId = roles.find(r => r.name === currentUserRole)?.id;
  const hasPermission = useCallback((permName: string) => {
      if (currentUserRole === 'ADMIN' && (permName === 'perm_tab_permissions' || permName === 'perm_manage_roles' || permName === 'perm_tab_settings')) return true;
      if (!currentRoleId) return false;
      return permissions.some(p => p.roleId === currentRoleId && p.permissionName === permName);
  }, [currentUserRole, currentRoleId, permissions]);

  const resolveName = useCallback((username?: string | null) => {
      if (!username) return '-';
      const u = users.find(x => x.username === username);
      return (u?.nickname || username).toUpperCase();
  }, [users]);

  const logisticsOperationsList = useMemo(() => props.logisticsOperations || [], [props.logisticsOperations]);

  const handleAdd = () => {
    if (entryMode === 'production') {
        if (!selectedPart || !selectedWorkplace || !quantity) { alert(t('fill_all_fields')); return; }
        // Pass empty note and isProduction = true
        onAddTask(selectedPart, selectedWorkplace, quantity, quantityUnit, priority, false, '', true);
    } else {
        if (!logisticsRef || !logisticsOp || !quantity) { alert(t('fill_all_fields')); return; }
        // Pass source/target sectors for logistics
        onAddTask(logisticsRef, logisticsOp, quantity, quantityUnit, priority, true, logisticsPlate, false, sourceSector || undefined, targetSector || undefined);
    }

    // Reset Form
    setSelectedPart(null); 
    setSelectedWorkplace(null); 
    setLogisticsRef(''); 
    setLogisticsOp(''); 
    setLogisticsPlate(''); 
    setSourceSector(null);
    setTargetSector(null);
    setQuantity('');
    setPriority('NORMAL'); 
    setShowSuccessMessage(true); 
    setTimeout(() => setShowSuccessMessage(false), 2000);
  };

  // LOGIKA KONTROLY SEKTORA PRED DOKONČENÍM
  const handleCompleteWithSectorCheck = (id: string) => {
    const task = tasks.find(t => t.id === id);
    if (!task) return;

    // Ak je to výrobná úloha, ide sa dokončiť (isDone je false) a chýba priradený sektor:
    if (!task.isLogistics && !task.isDone && !task.pickedFromSectorId) {
        setPickingTask(task);
        return;
    }
    onToggleTask(id);
  };

  return (
    <div className="flex flex-col h-screen bg-gray-900 text-white">
      <AppHeader currentUser={currentUser} currentUserRole={currentUserRole} users={users} onLogout={onLogout} language={language} setLanguage={setLanguage} t={t} isFullscreen={false} onToggleFullscreen={()=>{}} installPrompt={installPrompt} onInstallApp={onInstallApp} hasPermission={hasPermission} resolveName={resolveName} />

      {showSuccessMessage && (
        <div className="fixed top-24 right-6 bg-green-600 text-white px-6 py-4 rounded-xl shadow-2xl z-50 animate-bounce font-black tracking-widest">✓ {t('sent_msg')}</div>
      )}

      <TabNavigator activeTab={activeTab} setActiveTab={setActiveTab} hasPermission={hasPermission} t={t} counts={{ tasks: (tasks || []).filter(t=>!t.isDone).length, pendingRequests: (props.partRequests?.length || 0) + (props.bomRequests?.length || 0) }} />

      <div className="flex-grow overflow-y-auto p-3 md:p-8 custom-scrollbar">
          <div className="max-w-7xl mx-auto w-full">
          {activeTab === 'entry' && (
            <ProductionEntry 
                mode={entryMode} setMode={setMode => { setEntryMode(setMode); setQuantityUnit(setMode === 'logistics' ? 'pallet' : 'pcs'); }} 
                selectedPart={selectedPart} setSelectedPart={setSelectedPart} 
                selectedWorkplace={selectedWorkplace} setSelectedWorkplace={setSelectedWorkplace} 
                logisticsRef={logisticsRef} setLogisticsRef={setLogisticsRef} 
                logisticsPlate={logisticsPlate} setLogisticsPlate={setLogisticsPlate} 
                logisticsOp={logisticsOp} setLogisticsOp={setLogisticsOp} 
                sourceSector={sourceSector} setSourceSector={setSourceSector}
                targetSector={targetSector} setTargetSector={setTargetSector}
                quantity={quantity} setQuantity={setQuantity} 
                quantityUnit={quantityUnit} setQuantityUnit={setQuantityUnit} 
                priority={priority} setPriority={setPriority} 
                parts={(parts || []).map(p => p.value)} workplaces={workplaces} 
                logisticsOperationsList={logisticsOperationsList} 
                mapSectors={mapSectors}
                t={t} language={language} hasPermission={hasPermission} 
                handleAdd={handleAdd} onRequestPart={props.onRequestPart} 
                isUnitLocked={!!unitLock} 
            />
          )}
          {activeTab === 'analytics' && (
            <AnalyticsTab 
              tasks={tasks} 
              draftTasks={draftTasks}
              onFetchArchivedTasks={props.onFetchArchivedTasks} 
              fetchSanons={fetchSanons} 
              settings={settings} 
              systemBreaks={props.systemBreaks} 
              resolveName={resolveName} 
              mapSectors={mapSectors} 
              workplaces={workplaces} 
              systemConfig={systemConfig} 
              logisticsOperations={logisticsOperationsList} 
              users={users} 
              currentUser={currentUser} 
              currentUserRole={currentUserRole} 
              hasPermission={hasPermission} 
            />
          )}
          {activeTab === 'settings' && 
            <SettingsTab 
                hasPermission={hasPermission} 
                currentUserRole={currentUserRole} 
                currentUser={currentUser}
                users={users} 
                onAddUser={props.onAddUser} 
                onUpdatePassword={props.onUpdatePassword} 
                onUpdateNickname={props.onUpdateNickname} 
                onUpdateUserRole={props.onUpdateUserRole} 
                onDeleteUser={props.onDeleteUser} 
                onUpdateExportPermission={props.onUpdateExportPermission} 
                parts={parts} 
                workplaces={workplaces} 
                missingReasons={missingReasons} 
                onAddPart={props.onAddPart} 
                onBatchAddParts={props.onBatchAddParts} 
                onDeletePart={props.onDeletePart} 
                onDeleteAllParts={props.onDeleteAllParts} 
                onAddWorkplace={props.onAddWorkplace} 
                onUpdateWorkplace={props.onUpdateWorkplace} 
                onBatchAddWorkplaces={props.onBatchAddWorkplaces} 
                onDeleteWorkplace={props.onDeleteWorkplace} 
                onDeleteAllWorkplaces={props.onDeleteAllWorkplaces} 
                onAddMissingReason={props.onAddMissingReason} 
                onDeleteMissingReason={props.onDeleteMissingReason} 
                logisticsOperations={logisticsOperationsList} 
                onAddLogisticsOperation={props.onAddLogisticsOperation} 
                onUpdateLogisticsOperation={props.onUpdateLogisticsOperation} 
                onDeleteLogisticsOperation={props.onDeleteLogisticsOperation} 
                mapSectors={mapSectors} 
                onAddMapSector={props.onAddMapSector} 
                onDeleteMapSector={props.onDeleteMapSector} 
                onUpdateMapSector={props.onUpdateMapSector} 
                partRequests={props.partRequests} 
                onApprovePartRequest={onApprovePartRequest} 
                onRejectPartRequest={onRejectPartRequest} 
                onArchiveTasks={onArchiveTasks} 
                onDailyClosing={props.onDailyClosing} 
                onWeeklyClosing={props.onWeeklyClosing} 
                fetchSanons={fetchSanons} 
                breakSchedules={breakSchedules} 
                onAddBreakSchedule={props.onAddBreakSchedule} 
                onDeleteBreakSchedule={props.onDeleteBreakSchedule} 
                bomMap={bomMap} 
                bomRequests={bomRequests} 
                onAddBOMItem={props.onAddBOMItem} 
                onBatchAddBOMItems={props.onBatchAddBOMItems} 
                onDeleteBOMItem={props.onDeleteBOMItem} 
                onDeleteAllBOMItems={props.onDeleteAllBOMItems} 
                onApproveBOMRequest={onApproveBOMRequest} 
                onRejectBOMRequest={onRejectBOMRequest} 
                roles={roles} 
                permissions={permissions} 
                onAddRole={onAddRole} 
                onDeleteRole={onDeleteRole} 
                onUpdatePermission={onUpdatePermission} 
                installPrompt={null} 
                onInstallApp={()=>{}} 
                systemConfig={systemConfig} 
                onUpdateSystemConfig={onUpdateSystemConfig} 
                dbLoadWarning={dbLoadWarning} 
                resolveName={resolveName} 
                onGetDocCount={onGetDocCount} 
                onPurgeOldTasks={onPurgeOldTasks} 
                onExportTasksJSON={onExportTasksJSON} 
                onUpdateAdminKey={props.onUpdateAdminKey} 
                onToggleAdminLock={props.onToggleAdminLock}
                adminNotes={adminNotes}
                onAddAdminNote={onAddAdminNote}
                onDeleteAdminNote={onDeleteAdminNote}
                onClearAdminNotes={onClearAdminNotes}
            />}
          {activeTab === 'tasks' && (
            <div className="animate-fade-in pb-20">
              <div className="mb-6 flex justify-center">
                <input 
                  type="text" 
                  value={taskSearchQuery} 
                  onChange={e => setTaskSearchQuery(e.target.value)} 
                  className="w-full max-w-lg h-12 px-6 bg-gray-800 border border-gray-700 rounded-xl text-white placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-teal-500 transition-all font-mono uppercase" 
                  placeholder={t('task_search_placeholder')} 
                />
              </div>
              <TaskList 
                currentUser={currentUserRole} 
                currentUserName={currentUser} 
                tasks={(tasks || []).filter(t => { 
                  const q = taskSearchQuery.toLowerCase(); 
                  return (t.partNumber && t.partNumber.toLowerCase().includes(q)) || (t.text && t.text.toLowerCase().includes(q)) || (t.workplace && t.workplace.toLowerCase().includes(q)); 
                })} 
                onToggleTask={handleCompleteWithSectorCheck} 
                onEditTask={onEditTask} 
                onDeleteTask={onDeleteTask} 
                onToggleMissing={onToggleMissing} 
                onSetInProgress={onSetInProgress} 
                onToggleBlock={props.onToggleBlock} 
                onToggleManualBlock={onToggleManualBlock} 
                onExhaustSearch={onExhaustSearch} 
                onMarkAsIncorrect={onMarkAsIncorrect} 
                onAddNote={onAddNote} 
                onReleaseTask={onReleaseTask} 
                onAuditPart={props.onStartAudit}
                onFinishAudit={props.onFinishAudit} 
                resolveName={resolveName} 
                missingReasons={missingReasons} 
                hasPermission={hasPermission} 
              />
            </div>
          )}
          {activeTab === 'bom' && <BOMScreen parts={parts} workplaces={workplaces} bomMap={bomMap} onAddTask={onAddTask} onRequestBOM={props.onRequestBOM} t={t} language={language} />}
          {activeTab === 'missing' && <MissingItemsTab tasks={tasks} onDeleteMissingItem={props.onDeleteMissingItem} hasPermission={hasPermission} resolveName={resolveName} />}
          {activeTab === 'inventory' && <InventoryTab currentUser={currentUser} tasks={tasks} onAddTask={onAddTask} onUpdateTask={onUpdateTask} onToggleTask={onToggleTask} onDeleteTask={props.onDeleteTask} hasPermission={hasPermission} parts={(parts || []).map(p=>p.value)} onRequestPart={props.onRequestPart} resolveName={resolveName} />}
          {activeTab === 'logistics' && <LogisticsCenterTab tasks={tasks} onDeleteTask={props.onDeleteTask} hasPermission={hasPermission} resolveName={resolveName} />}
          {activeTab === 'permissions' && <PermissionsTab roles={roles} permissions={permissions} onAddRole={onAddRole} onDeleteRole={onDeleteRole} onUpdatePermission={onUpdatePermission} onVerifyAdminPassword={onVerifyAdminPassword} />}
          {activeTab === 'catalog' && <PartCatalogTab parts={parts} onSelectPart={p => { setSelectedPart(p.value); setActiveTab('entry'); }} />}
          </div>
      </div>

      {pickingTask && createPortal(
          <SectorPickerModal 
              task={pickingTask}
              mapSectors={props.mapSectors}
              onClose={() => setPickingTask(null)}
              onConfirm={(sectorId) => {
                  onUpdateTask(pickingTask.id, { pickedFromSectorId: sectorId });
                  onToggleTask(pickingTask.id);
                  setPickingTask(null);
              }}
          />,
          document.body
      )}
    </div>
  );
};

export default PartSearchScreen;

import React, { useMemo } from 'react';
import PartSearchScreen from './components/PartSearchScreen';
import NotificationModal from './components/modals/NotificationModal';
import { useData } from './context/DataContext';
import { SystemConfig, PriorityLevel, Task } from './types/appTypes';
import { db } from './firebase';
import { collection, addDoc } from 'firebase/firestore';

interface AppAuthenticatedProps {
  currentUser: string;
  currentUserRole: 'ADMIN' | 'USER' | 'LEADER';
  onLogout: () => void;
  systemConfig: SystemConfig;
  onUpdateSystemConfig: (config: Partial<SystemConfig>) => void;
  onUpdateAdminKey: (oldK: string, newK: string) => Promise<void>;
  onToggleAdminLock: (val: boolean) => void;
  installPrompt: any;
  onInstallApp: () => void;
}

const AppAuthenticated: React.FC<AppAuthenticatedProps> = (props) => {
  const data = useData();

  // Získanie notifikácií pre aktuálneho používateľa
  const myNotifications = useMemo(() => {
      if (!data || !data.notifications) return [];
      return data.notifications
        .filter(n => n.targetUser === props.currentUser)
        .sort((a, b) => b.timestamp - a.timestamp); // Najnovšie prvé, ale zobrazujeme ich postupne
  }, [data?.notifications, props.currentUser]);

  // Vyberieme prvú notifikáciu v rade na zobrazenie
  const activeNotification = myNotifications.length > 0 ? myNotifications[0] : null;

  const handleConfirmNotification = () => {
      if (activeNotification && data.onClearNotification) {
          data.onClearNotification(activeNotification.id);
      }
  };

  const resolveName = (username?: string | null) => {
      if (!username) return '-';
      const u = data?.users.find(x => x.username === username);
      return (u?.nickname || username).toUpperCase();
  };

  if (!data || !data.tasks || !data.users) {
      return (
          <div className="w-full h-full flex items-center justify-center bg-gray-900">
              <p className="text-white text-xl font-bold animate-pulse">Načítavam systém...</p>
          </div>
      );
  }

  const partsList = data.partsMap 
    ? Object.entries(data.partsMap).map(([p, d]) => ({ id: p, value: p, description: d }))
    : [];

  const safeGetDocCount = (data as any).onGetDocCount || (async () => 0);
  const safePurgeOldTasks = (data as any).onPurgeOldTasks || (async () => 0);
  const safeExportTasksJSON = (data as any).onExportTasksJSON || (async () => {});
  const safeFetchArchivedTasks = (data as any).onFetchArchivedTasks || (async () => []);
  const safeVerifyAdminPassword = (data as any).onVerifyAdminPassword || ((p: string) => false);
  const safeRequestPart = (data as any).onRequestPart || (async () => false);
  const safeRequestBOM = (data as any).onRequestBOM || (async () => false);
  const safeOnDailyClosing = (data as any).onDailyClosing || (async () => ({ success: false, count: 0 }));
  const safeOnWeeklyClosing = (data as any).onWeeklyClosing || (async () => ({ success: false, count: 0, sanon: '' }));
  const safeFetchSanons = (data as any).fetchSanons || (async () => []);

  // Admin Notes functions
  const safeAdminNotes = (data as any).adminNotes || [];
  const safeAddAdminNote = (data as any).onAddAdminNote || (() => {});
  const safeDeleteAdminNote = (data as any).onDeleteAdminNote || (() => {});
  const safeClearAdminNotes = (data as any).onClearAdminNotes || (() => {});

  const handleCreateInventoryTask = async (
      partNumber: string, 
      workplace: string | null, 
      quantity: string | null, 
      quantityUnit: string | null, 
      priority: PriorityLevel, 
      isLogistics: boolean = false, 
      noteOrPlate: string = '', 
      isProduction: boolean = false,
      sourceSectorId?: string,
      targetSectorId?: string
  ) => {
      if (partNumber === "Počítanie zásob") {
          try {
              await addDoc(collection(db, 'tasks'), {
                  partNumber, workplace: workplace || '', quantity: quantity || '0', quantityUnit: quantityUnit || 'pcs', priority, isLogistics, note: noteOrPlate, text: partNumber, status: 'unpacked', isInProgress: true, inProgressBy: props.currentUser, isDone: false, isMissing: false, createdAt: Date.now(), createdBy: props.currentUser, isProduction: !!isProduction
              });
          } catch (e) { console.error("Failed to create inventory task", e); }
      } else {
          try {
              const newTask: any = {
                  text: partNumber, partNumber, workplace: workplace || '', quantity: quantity || '0', quantityUnit: quantityUnit || 'pcs', priority, isLogistics, isProduction, note: isLogistics ? '' : noteOrPlate, plate: isLogistics ? noteOrPlate : '', isDone: false, isMissing: false, createdAt: Date.now(), createdBy: props.currentUser, status: 'open',
                  sourceSectorId: sourceSectorId || null,
                  targetSectorId: targetSectorId || null
              };
              await addDoc(collection(db, 'tasks'), newTask);
          } catch (e) { console.error("Error adding task", e); }
      }
  };

  const handleUpdateTask = (id: string, updates: any) => { if (data.onUpdateTask) data.onUpdateTask(id, updates); };
  const handleDeleteTask = (id: string) => { if (data.onDeleteTask) data.onDeleteTask(id); };

  const handleToggleTask = async (id: string) => {
      const task = data.tasks.find(t => t.id === id);
      if (!task) return;
      const updates: any = { isDone: !task.isDone };
      if (task.isDone) { updates.completedAt = null; updates.completedBy = null; updates.status = 'open'; updates.isInProgress = false; updates.inProgressBy = null; }
      else { updates.completedAt = Date.now(); updates.completedBy = props.currentUser; updates.status = 'completed'; }
      await data.onUpdateTask(id, updates);
  };

  const handleToggleManualBlock = async (id: string) => {
    const task = data.tasks.find(t => t.id === id);
    if (!task) return;
    const newBlockedState = !task.isManualBlocked;
    const updates: any = { isManualBlocked: newBlockedState };
    if (newBlockedState) { updates.isInProgress = false; updates.inProgressBy = null; updates.priority = 'LOW'; }
    else { updates.createdAt = Date.now(); }
    await data.onUpdateTask(id, updates);
  };

  const handleMarkAsIncorrect = async (id: string) => {
    await data.onUpdateTask(id, { isDone: true, status: 'incorrectly_entered', completedBy: props.currentUser, completedAt: Date.now(), isInProgress: false, inProgressBy: null });
  };

  const handleStartAudit = async (id: string) => {
     await data.onUpdateTask(id, { isAuditInProgress: true, auditBy: props.currentUser, isInProgress: false, inProgressBy: null });
  };

  const handleFinishAudit = async (id: string, result: 'found' | 'missing', note: string) => {
     const task = data.tasks.find(t => t.id === id);
     if (!task) return;
     const badgeText = result === 'found' ? `AUDIT (OK) - ${note}` : `AUDIT (NOK) - ${note}`;
     const updates: any = { isAuditInProgress: false, auditFinalBadge: badgeText, auditBy: null, auditResult: result === 'found' ? 'OK' : 'NOK', auditNote: note, auditedBy: props.currentUser, auditedAt: Date.now() };
     if (result === 'found') { updates.isMissing = false; }
     else { updates.isDone = true; updates.status = 'audit_error'; updates.completedBy = props.currentUser; updates.completedAt = Date.now(); updates.isInProgress = false; }
     await data.onUpdateTask(id, updates);
     if (data.onAddNotification && task.createdBy) {
         await data.onAddNotification({ partNumber: task.partNumber || 'Unknown', reason: `AUDIT: ${result.toUpperCase()} - ${note}`, reportedBy: props.currentUser, targetUser: task.createdBy, timestamp: Date.now() });
     }
  };

  const handleToggleMissing = async (id: string, reason?: string) => {
      await data.onToggleMissing(id, reason);
      if (reason) {
          await data.onUpdateTask(id, { isInProgress: false, inProgressBy: null });
          if (data.onAddNotification) {
              const task = data.tasks.find(t => t.id === id);
              if (task) { await data.onAddNotification({ partNumber: task.partNumber || 'Unknown', reason: `CHÝBA: ${reason}`, reportedBy: props.currentUser, targetUser: task.createdBy || '', timestamp: Date.now() }); }
          }
      }
  };

  return (
    <div className="w-full h-full">
        <PartSearchScreen
          {...(data as any)}
          onAddTask={handleCreateInventoryTask}
          onUpdateTask={handleUpdateTask}
          onDeleteTask={handleDeleteTask}
          onToggleTask={handleToggleTask}
          onToggleManualBlock={handleToggleManualBlock}
          onMarkAsIncorrect={handleMarkAsIncorrect}
          onStartAudit={handleStartAudit}
          onFinishAudit={handleFinishAudit}
          onToggleMissing={handleToggleMissing}
          onDeleteMissingItem={(id) => handleToggleMissing(id)}
          onGetDocCount={safeGetDocCount}
          onPurgeOldTasks={safePurgeOldTasks}
          onExportTasksJSON={safeExportTasksJSON}
          onFetchArchivedTasks={safeFetchArchivedTasks}
          onVerifyAdminPassword={safeVerifyAdminPassword}
          onRequestPart={safeRequestPart}
          onRequestBOM={safeRequestBOM}
          onDailyClosing={safeOnDailyClosing}
          onWeeklyClosing={safeOnWeeklyClosing}
          fetchSanons={safeFetchSanons}
          draftTasks={data.draftTasks || []}
          settings={{ draft: { data: data.draftTasks || [] } }}
          parts={partsList}
          currentUser={props.currentUser}
          currentUserRole={props.currentUserRole}
          onLogout={props.onLogout}
          systemConfig={props.systemConfig}
          onUpdateSystemConfig={props.onUpdateSystemConfig}
          onUpdateAdminKey={props.onUpdateAdminKey}
          onToggleAdminLock={props.onToggleAdminLock}
          installPrompt={props.installPrompt}
          onInstallApp={props.onInstallApp}
          dbLoadWarning={false}
          adminNotes={safeAdminNotes}
          onAddAdminNote={safeAddAdminNote}
          onDeleteAdminNote={safeDeleteAdminNote}
          onClearAdminNotes={safeClearAdminNotes}
        />

        {activeNotification && (
            <NotificationModal 
                notification={activeNotification}
                onConfirm={handleConfirmNotification}
                resolveName={resolveName}
            />
        )}
    </div>
  );
};

export default AppAuthenticated;

