          const isActive = activeSubTab === tile.id;
          return (
            <button 
              key={tile.id} 
              onClick={() => setActiveSubTab(tile.id)}
              className={`flex flex-col items-center justify-center p-6 rounded-3xl border-2 transition-all duration-300 group relative ${
                isActive 
