import React, { useState, useMemo } from 'react';
import { Task, UserData, MapSector, DBItem, SystemConfig } from '../../types/appTypes';
import { useLanguage } from '../LanguageContext';
import { COLOR_MAP } from '../../constants/uiConstants';

interface MapVisualizationTabProps {
  tasks: Task[];
  draftTasks: Task[];
  fetchSanons: () => Promise<any[]>;
  users: UserData[];
  mapSectors: MapSector[];
  workplaces: DBItem[];
  logisticsOperations: DBItem[];
  systemConfig: SystemConfig;
  resolveName: (username?: string | null) => string;
}

interface Point { x: number; y: number; label: string; type: 'wp' | 'sector' | 'log'; id: string; color?: string }
interface RouteSegment { from: Point; to: Point; worker: string; isTransit: boolean; taskType: 'prod' | 'log' }

const MapVisualizationTab: React.FC<MapVisualizationTabProps> = ({
  tasks, draftTasks, fetchSanons, users, mapSectors, workplaces, logisticsOperations, systemConfig, resolveName
}) => {
  const { t, language } = useLanguage();

  // Filtre
  const [dateFrom, setDateFrom] = useState(new Date().toISOString().split('T')[0]);
  const [dateTo, setDateTo] = useState(new Date().toISOString().split('T')[0]);
  const [selectedWorkers, setSelectedWorkers] = useState<string[]>([]);

  // Dáta
  const [allData, setAllData] = useState<Task[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  const handleLoadMap = async () => {
    setIsLoading(true);
    try {
        const sanons = await fetchSanons();
        const combined: Task[] = [...tasks, ...draftTasks];
        sanons.forEach(s => { if (s.tasks) combined.push(...s.tasks); });

        // Filter podľa unikátnosti a času
        const startTs = new Date(dateFrom).setHours(0,0,0,0);
        const endTs = new Date(dateTo).setHours(23,59,59,999);

        const filtered = combined.filter(t => {
            const ts = t.completedAt || t.createdAt || 0;
            return ts >= startTs && ts <= endTs && t.isDone;
        });

        const uniqueMap = new Map();
        filtered.forEach(t => uniqueMap.set(t.id, t));
        setAllData(Array.from(uniqueMap.values()));
    } catch (e) {
        console.error(e);
    } finally {
        setIsLoading(false);
    }
  };

  // Trajektórie
  const { segments, nodes, viewBox } = useMemo(() => {
    const workerSegments: RouteSegment[] = [];
    const pointsMap = new Map<string, Point>();

    // 1. Zber bodov (Nodes)
    workplaces.forEach(w => pointsMap.set(`wp_${w.value}`, { x: w.coordX || 0, y: w.coordY || 0, label: w.value, type: 'wp', id: w.id }));
    logisticsOperations.forEach(l => pointsMap.set(`log_${l.value}`, { x: l.coordX || 0, y: l.coordY || 0, label: l.value, type: 'log', id: l.id }));
    mapSectors.forEach(s => pointsMap.set(`sector_${s.id}`, { x: s.coordX || 0, y: s.coordY || 0, label: s.name, type: 'sector', id: s.id, color: s.color }));

    // 2. Generovanie segmentov
    const filteredByWorker = selectedWorkers.length > 0 
        ? allData.filter(t => selectedWorkers.includes(t.completedBy || '')) 
        : allData;

    const grouped = new Map<string, Task[]>();
    filteredByWorker.forEach(t => {
        const worker = t.completedBy || 'Unknown';
        if (!grouped.has(worker)) grouped.set(worker, []);
        grouped.get(worker)!.push(t);
    });

    grouped.forEach((workerTasks, worker) => {
        const sorted = [...workerTasks].sort((a,b) => (a.completedAt || 0) - (b.completedAt || 0));
        let prevEndPoint: Point | null = null;

        sorted.forEach(task => {
            let startNode: Point | null = null;
            let endNode: Point | null = null;

            if (task.isLogistics) {
                const op = pointsMap.get(`log_${task.workplace}`);
                const src = pointsMap.get(`sector_${task.sourceSectorId}`);
                const trg = pointsMap.get(`sector_${task.targetSectorId}`);

                // Priorita: Ak má operácia súradnice, je to cieľ. Ak sú definované sektory, ideme cez ne.
                startNode = src || op || null;
                endNode = trg || op || null;
            } else {
                startNode = pointsMap.get(`sector_${task.pickedFromSectorId}`) || null;
                endNode = pointsMap.get(`wp_${task.workplace}`) || null;
            }

            if (startNode && endNode) {
                // A. Transit (z minulej úlohy na štart tejto)
                if (prevEndPoint) {
                    workerSegments.push({ from: prevEndPoint, to: startNode, worker, isTransit: true, taskType: task.isLogistics ? 'log' : 'prod' });
                }
                // B. Práca (Ride)
                workerSegments.push({ from: startNode, to: endNode, worker, isTransit: false, taskType: task.isLogistics ? 'log' : 'prod' });
                prevEndPoint = endNode;
            }
        });
    });

    // 3. Výpočet ViewBox (Dynamický zoom)
    const allCoords = Array.from(pointsMap.values());
    if (allCoords.length === 0) return { segments: [], nodes: [], viewBox: "0 0 1000 1000" };

    const minX = Math.min(...allCoords.map(p => p.x)) - 50;
    const minY = Math.min(...allCoords.map(p => p.y)) - 50;
    const maxX = Math.max(...allCoords.map(p => p.x)) + 50;
    const maxY = Math.max(...allCoords.map(p => p.y)) + 50;

    return { 
        segments: workerSegments, 
        nodes: allCoords, 
        viewBox: `${minX} ${minY} ${maxX - minX} ${maxY - minY}` 
    };
  }, [allData, selectedWorkers, workplaces, logisticsOperations, mapSectors]);

  // UI Helpers
  const toggleWorker = (id: string) => {
      setSelectedWorkers(prev => prev.includes(id) ? prev.filter(w => w !== id) : [...prev, id]);
  };

  return (
    <div className="max-w-7xl mx-auto space-y-6 pb-20 animate-fade-in px-2 md:px-0">

        {/* CONTROL PANEL */}
        <div className="bg-slate-900 border border-slate-700 rounded-2xl p-5 shadow-xl">
            <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
                <div className="md:col-span-1 space-y-4">
                    <h3 className="text-sm font-black text-amber-500 uppercase tracking-widest border-b border-amber-900/30 pb-2">Časový rozsah</h3>
                    <div className="grid grid-cols-2 gap-2">
                        <input type="date" value={dateFrom} onChange={e => setDateFrom(e.target.value)} className="bg-slate-950 border border-slate-700 rounded-lg px-3 py-2 text-xs text-white outline-none" />
                        <input type="date" value={dateTo} onChange={e => setDateTo(e.target.value)} className="bg-slate-950 border border-slate-700 rounded-lg px-3 py-2 text-xs text-white outline-none" />
                    </div>
                    <button 
                        onClick={handleLoadMap} 
                        disabled={isLoading}
                        className="w-full h-12 bg-amber-600 hover:bg-amber-500 text-white font-black rounded-xl uppercase text-xs tracking-widest shadow-lg transition-all active:scale-95 flex items-center justify-center gap-2 border-2 border-amber-500"
                    >
                        {isLoading ? '...' : '🔄 ' + t('map_load_btn')}
                    </button>
                </div>

                <div className="md:col-span-2 space-y-4 border-l border-slate-800 pl-6">
                    <h3 className="text-sm font-black text-slate-400 uppercase tracking-widest border-b border-slate-800 pb-2">{t('map_filter_workers')}</h3>
                    <div className="flex flex-wrap gap-2 max-h-24 overflow-y-auto custom-scrollbar">
                        {users.map(u => (
                            <button 
                                key={u.username}
                                onClick={() => toggleWorker(u.username)}
                                className={`px-3 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest border transition-all ${selectedWorkers.includes(u.username) ? 'bg-teal-500 border-teal-400 text-white shadow-[0_0_10px_rgba(20,184,166,0.3)]' : 'bg-slate-800 border-slate-700 text-slate-500 hover:text-slate-300'}`}
                            >
                                {u.nickname || u.username}
                            </button>
                        ))}
                    </div>
                </div>

                <div className="md:col-span-1 space-y-4 border-l border-slate-800 pl-6">
                    <h3 className="text-sm font-black text-slate-400 uppercase tracking-widest border-b border-slate-800 pb-2">Legenda</h3>
                    <div className="grid grid-cols-2 gap-y-2">
                        <div className="flex items-center gap-2 text-[9px] font-bold text-slate-500 uppercase">
                            <span className="w-4 h-1 bg-teal-500 rounded"></span> {t('map_legend_full')}
                        </div>
                        <div className="flex items-center gap-2 text-[9px] font-bold text-slate-500 uppercase">
                            <span className="w-4 h-0.5 bg-slate-600 border-b border-dashed"></span> {t('map_legend_empty')}
                        </div>
                        <div className="flex items-center gap-2 text-[9px] font-bold text-slate-500 uppercase">
                            <span className="w-3 h-3 rounded-full bg-blue-500"></span> {t('map_legend_wp')}
                        </div>
                        <div className="flex items-center gap-2 text-[9px] font-bold text-slate-500 uppercase">
                            <span className="w-3 h-3 bg-pink-500"></span> {t('map_legend_sector')}
                        </div>
                    </div>
                </div>
            </div>
        </div>

        {/* MAP VISUALIZATION AREA */}
        <div className="bg-slate-900 border-2 border-slate-800 rounded-3xl shadow-2xl overflow-hidden relative min-h-[600px] flex flex-col">
            {isLoading && (
                <div className="absolute inset-0 bg-slate-900/80 backdrop-blur-sm z-50 flex flex-col items-center justify-center gap-4">
                    <div className="w-12 h-12 border-4 border-amber-500 border-t-transparent rounded-full animate-spin"></div>
                    <p className="text-amber-500 font-black animate-pulse uppercase tracking-[0.3em]">{t('map_loading')}</p>
                </div>
            )}

            <div className="flex-grow relative cursor-crosshair">
                <svg 
                    viewBox={viewBox} 
                    className="w-full h-full min-h-[600px] preserve-3d" 
                    xmlns="http://www.w3.org/2000/svg"
                >
                    {/* Grid Background */}
                    <defs>
                        <pattern id="grid" width="100" height="100" patternUnits="userSpaceOnUse">
                            <path d="M 100 0 L 0 0 0 100" fill="none" stroke="white" strokeWidth="0.5" strokeOpacity="0.03" />
                        </pattern>
                    </defs>
                    <rect width="10000" height="10000" x="-5000" y="-5000" fill="url(#grid)" />

                    {/* ROUTES - Transit (Layer 1) */}
                    {segments.filter(s => s.isTransit).map((s, i) => (
                        <line 
                            key={`transit-${i}`}
                            x1={s.from.x} y1={s.from.y} x2={s.to.x} y2={s.to.y}
                            stroke="#475569" strokeWidth="1.5" strokeDasharray="4 4" strokeOpacity="0.4"
                        />
                    ))}

                    {/* ROUTES - Work (Layer 2) */}
                    {segments.filter(s => !s.isTransit).map((s, i) => (
                        <line 
                            key={`ride-${i}`}
                            x1={s.from.x} y1={s.from.y} x2={s.to.x} y2={s.to.y}
                            stroke={s.taskType === 'prod' ? '#14b8a6' : '#0ea5e9'} 
                            strokeWidth="3" strokeLinecap="round" strokeOpacity="0.7"
                            className="hover:stroke-white hover:strokeOpacity-100 transition-all cursor-pointer"
                        >
                            <title>{resolveName(s.worker)} | {s.from.label} → {s.to.label}</title>
                        </line>
                    ))}

                    {/* NODES - Workplaces (Layer 3) */}
                    {nodes.map(node => {
                        const isSector = node.type === 'sector';
                        const colorClass = isSector ? (node.color === 'slate' ? '#475569' : node.color === 'blue' ? '#2563eb' : node.color === 'green' ? '#059669' : node.color === 'orange' ? '#d97706' : node.color === 'teal' ? '#0d9488' : node.color === 'pink' ? '#db2777' : '#dc2626') : '#2563eb';

                        return (
                            <g key={node.id} transform={`translate(${node.x}, ${node.y})`} className="group">
                                {isSector ? (
                                    <rect x="-10" y="-10" width="20" height="20" rx="4" fill={colorClass} fillOpacity="0.3" stroke={colorClass} strokeWidth="1.5" />
                                ) : (
                                    <circle r="8" fill="#1e293b" stroke={node.type === 'wp' ? '#3b82f6' : '#0ea5e9'} strokeWidth="2" />
                                )}
                                <text 
                                    y={isSector ? -15 : -12} 
                                    textAnchor="middle" 
                                    fill="white" 
                                    className="text-[8px] font-black uppercase tracking-tighter opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none drop-shadow-md"
                                >
                                    {node.label}
                                </text>
                            </g>
                        );
                    })}
                </svg>
            </div>

            {allData.length === 0 && !isLoading && (
                <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-700 pointer-events-none">
                    <svg className="w-20 h-20 mb-4 opacity-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M9 20l-5.447-2.724A1 1 0 013 16.382V5.618a1 1 0 011.447-.894L9 7m0 13l6-3m-6 3V7m6 10l4.553 2.276A1 1 0 0021 18.382V7.618a1 1 0 00-.553-.894L15 4m0 13V4m0 0L9 7" /></svg>
                    <p className="text-xs font-black uppercase tracking-widest opacity-20">Zadajte filter a vygenerujte mapu</p>
                </div>
            )}
        </div>

        <div className="text-center">
            <p className="text-[10px] text-slate-600 font-bold uppercase tracking-widest italic">
                * Mapa zobrazuje body na základe pixelových súradníc z databázy. Smer jazdy je určený z postupnosti dokončenia úloh.
            </p>
        </div>
    </div>
  );
};

export default MapVisualizationTab;

import React, { useState, useMemo, useEffect, useCallback } from 'react';
import { createPortal } from 'react-dom';
import TaskList from './tabs/TaskList';
import SettingsTab from './settings/SettingsTab';
import AnalyticsTab from './tabs/Analytics/AnalyticsTab';
import MissingItemsTab from './tabs/MissingItemsTab';
import LogisticsCenterTab from './tabs/LogisticsCenterTab';
import InventoryTab from './tabs/InventoryTab';
