declare var XLSX: any;

interface PartSearchScreenProps {
  currentUser: string;
  currentUserRole: 'ADMIN' | 'USER' | 'LEADER';
  onLogout: () => void;
  tasks: Task[];
  draftTasks: Task[];
  onAddTask: (partNumber: string, workplace: string | null, quantity: string | null, quantityUnit: string | null, priority: PriorityLevel, isLogistics?: boolean, note?: string, isProduction?: boolean, sourceSectorId?: string, targetSectorId?: string) => void; 
  onUpdateTask: (id: string, updates: Partial<Task>) => void;
  onToggleTask: (id: string) => void;
  onMarkAsIncorrect: (id: string) => void;
  onEditTask: (id: string, newText: string, newPriority?: PriorityLevel) => void;
  onDeleteTask: (id: string) => void;
  onToggleMissing: (id: string, reason?: string) => void; 
  onSetInProgress: (id: string) => void;
  onToggleBlock: (id: string) => void; 
  onToggleManualBlock: (id: string) => void;
  onExhaustSearch: (id: string) => void;
  onAddCodeNote?: (id: string, note: string) => void; // Renamed if needed, but not in current interface
  onAddNote: (id: string, note: string) => void;
  onDeleteMissingItem: (id: string) => void;
  onDeleteMissingReason: (id: string) => void;
  onReleaseTask: (id: string) => void;
  onArchiveTasks: () => Promise<{ success: boolean; count?: number }>;
  onDailyClosing: () => Promise<{ success: boolean; count: number }>;
  onWeeklyClosing: () => Promise<{ success: boolean; count: number; sanon?: string }>;
  onFetchArchivedTasks: () => Promise<Task[]>;
  fetchSanons: () => Promise<any[]>;
  onStartAudit: (id: string) => void;
  onFinishAudit: (id: string, result: 'found' | 'missing', note: string) => void;
  onVerifyAdminPassword: (password: string) => boolean;
  onGetDocCount: () => Promise<number>;
  onPurgeOldTasks: () => Promise<number>;
  onExportTasksJSON: () => Promise<void>;
  users: UserData[];
  onAddUser: (user: UserData) => void;
  onUpdatePassword: (username: string, newPass: string) => void;
  onUpdateNickname: (username: string, newNick: string) => void;
  onUpdateUserRole: (username: string, newRole: any) => void;
  onDeleteUser: (username: string) => void;
  onUpdateExportPermission: (username: string, canExport: boolean) => void;
  parts: DBItem[];
  workplaces: DBItem[];
  missingReasons: DBItem[];
  onAddPart: (val: string, desc?: string) => void;
  onBatchAddParts: (vals: string[]) => void;
  onDeletePart: (val: string) => void;
  onDeleteAllParts: () => void;
  onAddWorkplace: (val: string, time?: number, x?: number, y?: number) => void;
  onUpdateWorkplace: (id: string, updates: Partial<DBItem>) => void;
  onBatchAddWorkplaces: (vals: string[]) => void;
  onDeleteWorkplace: (id: string) => void;
  onDeleteAllWorkplaces: () => void;
  onAddMissingReason: (val: string) => void;
  logisticsOperations: DBItem[];
  onAddLogisticsOperation: (val: string, time?: number, dist?: number) => void; 
  onUpdateLogisticsOperation: (id: string, updates: Partial<DBItem>) => void;
  onDeleteLogisticsOperation: (id: string) => void;
  mapSectors: MapSector[];
  onAddMapSector: (name: string, x: number, y: number, color?: string) => void;
  onDeleteMapSector: (id: string) => void;
  onUpdateMapSector: (id: string, updates: Partial<MapSector>) => void;
  partRequests: PartRequest[];
  onRequestPart: (part: string) => Promise<boolean>;
  onApprovePartRequest: (req: PartRequest) => void;
  onRejectPartRequest: (id: string) => void;
  breakSchedules: BreakSchedule[];
  systemBreaks: SystemBreak[];
  isBreakActive: boolean;
  onAddBreakSchedule: (start: string, end: string) => void;
  onDeleteBreakSchedule: (id: string) => void;
  bomMap: Record<string, BOMComponent[]>;
  bomRequests: any[];
  onAddBOMItem: (parent: string, child: string, qty: number) => void;
  onBatchAddBOMItems: (vals: string[]) => void;
  onDeleteBOMItem: (parent: string, child: string) => void;
  onDeleteAllBOMItems: () => void;
  onRequestBOM: (parent: string) => Promise<boolean>;
  onApproveBOMRequest: (req: any) => void;
  onRejectBOMRequest: (id: string) => void;
  roles: Role[];
  permissions: Permission[];
  onAddRole: (name: string) => void;
  onDeleteRole: (id: string) => void;
  onUpdatePermission: (permissionId: string, roleName: string, hasPermission: boolean) => void;
  notifications: AppNotification[];
  onClearNotification: (id: string) => void;
  installPrompt: any;
  onInstallApp: () => void;
  systemConfig: SystemConfig;
  onUpdateSystemConfig: (config: Partial<SystemConfig>) => void;
  dbLoadWarning: boolean;
  onUpdateAdminKey: (oldK: string, newK: string) => Promise<void>;
  onToggleAdminLock: (val: boolean) => void;
  settings?: any;
  adminNotes: AdminNote[];
  onAddAdminNote: (text: string, author: string) => void;
  onDeleteAdminNote: (id: string) => void;
  onClearAdminNotes: () => void;
}

const PartSearchScreen: React.FC<PartSearchScreenProps> = (props) => {
  const { 
    currentUser, currentUserRole, onLogout, tasks, draftTasks, onAddTask, onUpdateTask, roles, permissions,
    notifications, onClearNotification, installPrompt, onInstallApp, parts, workplaces,
    onToggleTask, onEditTask, onDeleteTask, onToggleMissing, onSetInProgress, onToggleManualBlock, onExhaustSearch, onMarkAsIncorrect, onAddNote, onReleaseTask, missingReasons,
    users, fetchSanons,
    breakSchedules,
    bomMap,
    onAddRole, onDeleteRole, onUpdatePermission, onVerifyAdminPassword,
    systemConfig, onUpdateSystemConfig,
    mapSectors, isBreakActive
  } = props;

  const { t, language, setLanguage } = useLanguage();
  const [activeTab, setActiveTab] = useState<'entry' | 'tasks' | 'settings' | 'analytics' | 'bom' | 'missing' | 'logistics' | 'permissions' | 'inventory' | 'catalog' | 'logs' | 'map'>('entry');
  const [taskSearchQuery, setTaskSearchQuery] = useState('');
  const [entryMode, setEntryMode] = useState<'production' | 'logistics'>('production');

  const [pickingTask, setPickingTask] = useState<Task | null>(null);

  const [selectedPart, setSelectedPart] = useState<string | null>(null);
  const [selectedWorkplace, setSelectedWorkplace] = useState<string | null>(null);

  const [logisticsRef, setLogisticsRef] = useState('');
  const [logisticsOp, setLogisticsOp] = useState('');
  const [logisticsPlate, setLogisticsPlate] = useState('');
  const [sourceSector, setSourceSector] = useState<string | null>(null);
  const [targetSector, setTargetSector] = useState<string | null>(null);

  const [quantity, setQuantity] = useState<string>('');
  const [quantityUnit, setQuantityUnit] = useState<'pcs' | 'boxes' | 'pallet'>('pcs');
  const [priority, setPriority] = useState<PriorityLevel>('NORMAL');
  const [showSuccessMessage, setShowSuccessMessage] = useState(false);

  const unitLock = useMemo(() => {
    if (entryMode === 'logistics' || !selectedPart) return null;
    const partData = parts.find(p => p.value === selectedPart);
    const desc = partData?.description || '';
    if (desc.includes('S0001S')) return 'pcs';
    if (desc.includes('S0002S')) return 'boxes';
    if (desc.includes('S0003S')) return 'pallet';
    return null;
  }, [selectedPart, entryMode, parts]);

  useEffect(() => { if (unitLock) setQuantityUnit(unitLock); }, [unitLock]);

  const currentRoleId = roles.find(r => r.name === currentUserRole)?.id;
  const hasPermission = useCallback((permName: string) => {
      if (currentUserRole === 'ADMIN' && (permName === 'perm_tab_permissions' || permName === 'perm_manage_roles' || permName === 'perm_tab_settings' || permName === 'perm_tab_map')) return true;
      if (!currentRoleId) return false;
      return permissions.some(p => p.roleId === currentRoleId && p.permissionName === permName);
  }, [currentUserRole, currentRoleId, permissions]);

  const resolveName = useCallback((username?: string | null) => {
      if (!username) return '-';
      const u = users.find(x => x.username === username);
      return (u?.nickname || username).toUpperCase();
  }, [users]);

  const logisticsOperationsList = useMemo(() => props.logisticsOperations || [], [props.logisticsOperations]);

  const handleAdd = () => {
    if (isBreakActive && currentUserRole !== 'ADMIN') {
        alert(t('break_blocked_msg'));
        return;
    }

    if (entryMode === 'production') {
        if (!selectedPart || !selectedWorkplace || !quantity) { alert(t('fill_all_fields')); return; }
        onAddTask(selectedPart, selectedWorkplace, quantity, quantityUnit, priority, false, '', true);
    } else {
        if (!logisticsRef || !logisticsOp || !quantity) { alert(t('fill_all_fields')); return; }
        onAddTask(logisticsRef, logisticsOp, quantity, quantityUnit, priority, true, logisticsPlate, false, sourceSector || undefined, targetSector || undefined);
    }

    setSelectedPart(null); 
    setSelectedWorkplace(null); 
    setLogisticsRef(''); 
    setLogisticsOp(''); 
    setLogisticsPlate(''); 
    setSourceSector(null);
    setTargetSector(null);
    setQuantity('');
    setPriority('NORMAL'); 
    setShowSuccessMessage(true); 
    setTimeout(() => setShowSuccessMessage(false), 2000);
  };

  const handleCompleteWithSectorCheck = (id: string) => {
    const task = tasks.find(t => t.id === id);
    if (!task) return;
    if (!task.isLogistics && !task.isDone && !task.pickedFromSectorId) {
        setPickingTask(task);
        return;
    }
    onToggleTask(id);
  };

  return (
    <div className="flex flex-col h-screen bg-gray-900 text-white">
      <AppHeader currentUser={currentUser} currentUserRole={currentUserRole} users={users} onLogout={onLogout} language={language} setLanguage={setLanguage} t={t} isFullscreen={false} onToggleFullscreen={()=>{}} installPrompt={installPrompt} onInstallApp={onInstallApp} hasPermission={hasPermission} resolveName={resolveName} isBreakActive={isBreakActive} />

      {showSuccessMessage && (
        <div className="fixed top-24 right-6 bg-green-600 text-white px-6 py-4 rounded-xl shadow-2xl z-50 animate-bounce font-black tracking-widest">✓ {t('sent_msg')}</div>
      )}

      <TabNavigator activeTab={activeTab} setActiveTab={setActiveTab} hasPermission={hasPermission} t={t} counts={{ tasks: (tasks || []).filter(t=>!t.isDone).length, pendingRequests: (props.partRequests?.length || 0) + (props.bomRequests?.length || 0) }} currentUserRole={currentUserRole} />

      <div className="flex-grow overflow-y-auto p-3 md:p-8 custom-scrollbar">
          <div className="max-w-7xl mx-auto w-full">
          {activeTab === 'entry' && (
            <ProductionEntry 
                mode={entryMode} setMode={setMode => { setEntryMode(setMode); setQuantityUnit(setMode === 'logistics' ? 'pallet' : 'pcs'); }} 
                selectedPart={selectedPart} setSelectedPart={setSelectedPart} 
                selectedWorkplace={selectedWorkplace} setSelectedWorkplace={setSelectedWorkplace} 
                logisticsRef={logisticsRef} setLogisticsRef={setLogisticsRef} 
                logisticsPlate={logisticsPlate} setLogisticsPlate={setLogisticsPlate} 
                logisticsOp={logisticsOp} setLogisticsOp={setLogisticsOp} 
                sourceSector={sourceSector} setSourceSector={setSourceSector}
                targetSector={targetSector} setTargetSector={setTargetSector}
                quantity={quantity} setQuantity={setQuantity} 
                quantityUnit={quantityUnit} setQuantityUnit={setQuantityUnit} 
                priority={priority} setPriority={setPriority} 
                parts={(parts || []).map(p => p.value)} workplaces={workplaces} 
                logisticsOperationsList={logisticsOperationsList} 
                mapSectors={mapSectors}
                t={t} language={language} hasPermission={hasPermission} 
                handleAdd={handleAdd} onRequestPart={props.onRequestPart} 
                isUnitLocked={!!unitLock} 
            />
          )}
          {activeTab === 'analytics' && (
            <AnalyticsTab 
              systemConfig={systemConfig} 
              currentUser={currentUser} 
              currentUserRole={currentUserRole} 
              hasPermission={hasPermission} 
            />
          )}
          {activeTab === 'settings' && 
            <SettingsTab 
                currentUserRole={currentUserRole} 
                currentUser={currentUser}
                installPrompt={null} 
                onInstallApp={()=>{}} 
                systemConfig={systemConfig} 
                onUpdateSystemConfig={onUpdateSystemConfig} 
                onUpdateAdminKey={props.onUpdateAdminKey} 
                onToggleAdminLock={props.onToggleAdminLock}
            />}
          {activeTab === 'tasks' && (
            <div className="animate-fade-in pb-20">
              <div className="mb-6 flex justify-center">
                <input 
                  type="text" 
                  value={taskSearchQuery} 
                  onChange={e => setTaskSearchQuery(e.target.value)} 
                  className="w-full max-w-lg h-12 px-6 bg-gray-800 border border-gray-700 rounded-xl text-white placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-teal-500 transition-all font-mono uppercase" 
                  placeholder={t('task_search_placeholder')} 
                />
              </div>
              <TaskList 
                currentUser={currentUserRole} 
                currentUserName={currentUser} 
                tasks={(tasks || []).filter(t => { 
                  const q = taskSearchQuery.toLowerCase(); 
                  return (t.partNumber && t.partNumber.toLowerCase().includes(q)) || (t.text && t.text.toLowerCase().includes(q)) || (t.workplace && t.workplace.toLowerCase().includes(q)); 
                })} 
                onToggleTask={handleCompleteWithSectorCheck} 
                onEditTask={onEditTask} 
                onDeleteTask={onDeleteTask} 
                onToggleMissing={onToggleMissing} 
                onSetInProgress={onSetInProgress} 
                onToggleBlock={props.onToggleBlock} 
                onToggleManualBlock={props.onToggleManualBlock} 
                onExhaustSearch={onExhaustSearch} 
                onMarkAsIncorrect={onMarkAsIncorrect} 
                onAddNote={onAddNote} 
                onReleaseTask={onReleaseTask} 
                onAuditPart={props.onStartAudit}
                onFinishAudit={props.onFinishAudit} 
                resolveName={resolveName} 
                missingReasons={missingReasons} 
                hasPermission={hasPermission} 
              />
            </div>
          )}
          {activeTab === 'bom' && <BOMScreen parts={parts} workplaces={workplaces} bomMap={bomMap} onAddTask={onAddTask} onRequestBOM={props.onRequestBOM} t={t} language={language} />}
          {activeTab === 'missing' && <MissingItemsTab tasks={tasks} onDeleteMissingItem={props.onDeleteMissingItem} hasPermission={hasPermission} resolveName={resolveName} />}
          {activeTab === 'inventory' && <InventoryTab currentUser={currentUser} tasks={tasks} onAddTask={onAddTask} onUpdateTask={onUpdateTask} onToggleTask={onToggleTask} onDeleteTask={props.onDeleteTask} hasPermission={hasPermission} parts={(parts || []).map(p=>p.value)} onRequestPart={props.onRequestPart} resolveName={resolveName} />}
          {activeTab === 'logistics' && <LogisticsCenterTab tasks={tasks} onDeleteTask={props.onDeleteTask} hasPermission={hasPermission} resolveName={resolveName} />}
          {activeTab === 'permissions' && <PermissionsTab roles={roles} permissions={permissions} onAddRole={onAddRole} onDeleteRole={onDeleteRole} onUpdatePermission={onUpdatePermission} onVerifyAdminPassword={onVerifyAdminPassword} />}
          {activeTab === 'catalog' && <PartCatalogTab parts={parts} onSelectPart={p => { setSelectedPart(p.value); setActiveTab('entry'); }} />}
          {activeTab === 'logs' && currentUserRole === 'ADMIN' && (
              <TransactionLogTab 
                  tasks={tasks}
                  draftTasks={draftTasks}
                  fetchSanons={fetchSanons}
                  users={users}
                  mapSectors={mapSectors}
                  resolveName={resolveName}
              />
          )}
          {activeTab === 'map' && (
              <MapVisualizationTab 
                tasks={tasks}
                draftTasks={draftTasks}
                fetchSanons={fetchSanons}
                users={users}
                mapSectors={mapSectors}
                workplaces={workplaces}
                logisticsOperations={logisticsOperationsList}
                systemConfig={systemConfig}
                resolveName={resolveName}
              />
          )}
          </div>
      </div>

      {pickingTask && createPortal(
          <SectorPickerModal 
              task={pickingTask}
              mapSectors={props.mapSectors}
              onClose={() => setPickingTask(null)}
              onConfirm={(sectorId) => {
                  onUpdateTask(pickingTask.id, { pickedFromSectorId: sectorId });
                  onToggleTask(pickingTask.id);
                  setPickingTask(null);
              }}
          />,
          document.body
      )}
    </div>
  );
};

export default PartSearchScreen;

import React, { useState, useMemo } from 'react';
import { Task, UserData, MapSector, DBItem, SystemConfig } from '../../types/appTypes';
import { useLanguage } from '../LanguageContext';
import { COLOR_MAP } from '../../constants/uiConstants';

interface MapVisualizationTabProps {
  tasks: Task[];
  draftTasks: Task[];
  fetchSanons: () => Promise<any[]>;
  users: UserData[];
  mapSectors: MapSector[];
  workplaces: DBItem[];
  logisticsOperations: DBItem[];
  systemConfig: SystemConfig;
  resolveName: (username?: string | null) => string;
}

interface Point { x: number; y: number; label: string; type: 'wp' | 'sector' | 'log'; id: string; color?: string }
interface RouteSegment { from: Point; to: Point; worker: string; isTransit: boolean; taskType: 'prod' | 'log' }

const MapVisualizationTab: React.FC<MapVisualizationTabProps> = ({
  tasks, draftTasks, fetchSanons, users, mapSectors, workplaces, logisticsOperations, systemConfig, resolveName
}) => {
  const { t, language } = useLanguage();

  // Filtre
  const [dateFrom, setDateFrom] = useState(new Date().toISOString().split('T')[0]);
  const [dateTo, setDateTo] = useState(new Date().toISOString().split('T')[0]);
  const [selectedWorkers, setSelectedWorkers] = useState<string[]>([]);

  // Dáta
  const [allData, setAllData] = useState<Task[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  const handleLoadMap = async () => {
    setIsLoading(true);
    try {
        const sanons = await fetchSanons();
        const combined: Task[] = [...tasks, ...draftTasks];
        sanons.forEach(s => { if (s.tasks) combined.push(...s.tasks); });

        const startTs = new Date(dateFrom).setHours(0,0,0,0);
        const endTs = new Date(dateTo).setHours(23,59,59,999);

        const filtered = combined.filter(t => {
            const ts = t.completedAt || t.createdAt || 0;
            return ts >= startTs && ts <= endTs && t.isDone;
        });

        const uniqueMap = new Map();
        filtered.forEach(t => uniqueMap.set(t.id, t));
        setAllData(Array.from(uniqueMap.values()));
    } catch (e) {
        console.error(e);
    } finally {
        setIsLoading(false);
    }
  };

  // Trajektórie
  const { segments, nodes, viewBox } = useMemo(() => {
    const workerSegments: RouteSegment[] = [];
    const pointsMap = new Map<string, Point>();

    // 1. Zber bodov (Nodes)
    workplaces.forEach(w => pointsMap.set(`wp_${w.value}`, { x: w.coordX || 0, y: w.coordY || 0, label: w.value, type: 'wp', id: w.id }));
    logisticsOperations.forEach(l => pointsMap.set(`log_${l.value}`, { x: l.coordX || 0, y: l.coordY || 0, label: l.value, type: 'log', id: l.id }));
    mapSectors.forEach(s => pointsMap.set(`sector_${s.id}`, { x: s.coordX || 0, y: s.coordY || 0, label: s.name, type: 'sector', id: s.id, color: s.color }));

    // 2. Generovanie segmentov
    const filteredByWorker = selectedWorkers.length > 0 
        ? allData.filter(t => selectedWorkers.includes(t.completedBy || '')) 
        : allData;

    const grouped = new Map<string, Task[]>();
    filteredByWorker.forEach(t => {
        const worker = t.completedBy || 'Unknown';
        if (!grouped.has(worker)) grouped.set(worker, []);
        grouped.get(worker)!.push(t);
    });

    grouped.forEach((workerTasks, worker) => {
        const sorted = [...workerTasks].sort((a,b) => (a.completedAt || 0) - (b.completedAt || 0));
        let prevEndPoint: Point | null = null;

        sorted.forEach(task => {
            let startNode: Point | null = null;
            let endNode: Point | null = null;

            if (task.isLogistics) {
                const op = pointsMap.get(`log_${task.workplace}`);
                const src = pointsMap.get(`sector_${task.sourceSectorId}`);
                const trg = pointsMap.get(`sector_${task.targetSectorId}`);
                startNode = src || op || null;
                endNode = trg || op || null;
            } else {
                startNode = pointsMap.get(`sector_${task.pickedFromSectorId}`) || null;
                endNode = pointsMap.get(`wp_${task.workplace}`) || null;
            }

            if (startNode && endNode) {
                if (prevEndPoint) {
                    workerSegments.push({ from: prevEndPoint, to: startNode, worker, isTransit: true, taskType: task.isLogistics ? 'log' : 'prod' });
                }
                workerSegments.push({ from: startNode, to: endNode, worker, isTransit: false, taskType: task.isLogistics ? 'log' : 'prod' });
                prevEndPoint = endNode;
            }
        });
    });

    const allCoords = Array.from(pointsMap.values());
    if (allCoords.length === 0) return { segments: [], nodes: [], viewBox: "0 0 1000 1000" };

    const minX = Math.min(...allCoords.map(p => p.x)) - 100;
    const minY = Math.min(...allCoords.map(p => p.y)) - 100;
    const maxX = Math.max(...allCoords.map(p => p.x)) + 100;
    const maxY = Math.max(...allCoords.map(p => p.y)) + 100;

    return { 
        segments: workerSegments, 
        nodes: allCoords, 
        viewBox: `${minX} ${minY} ${maxX - minX} ${maxY - minY}` 
    };
  }, [allData, selectedWorkers, workplaces, logisticsOperations, mapSectors]);

  // Manhattan Path Helper
  const getManhattanPath = (from: Point, to: Point) => {
    // Vytvorí trasu v tvare písmena L (najskôr horizontálne, potom vertikálne)
    return `M ${from.x} ${from.y} L ${to.x} ${from.y} L ${to.x} ${to.y}`;
  };

  const toggleWorker = (id: string) => {
      setSelectedWorkers(prev => prev.includes(id) ? prev.filter(w => w !== id) : [...prev, id]);
  };

  return (
    <div className="max-w-7xl mx-auto space-y-6 pb-20 animate-fade-in px-2 md:px-0">

        {/* CONTROL PANEL */}
        <div className="bg-slate-900 border border-slate-700 rounded-2xl p-5 shadow-xl">
            <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
                <div className="md:col-span-1 space-y-4">
                    <h3 className="text-sm font-black text-amber-500 uppercase tracking-widest border-b border-amber-900/30 pb-2">Analytické obdobie</h3>
                    <div className="grid grid-cols-2 gap-2">
                        <input type="date" value={dateFrom} onChange={e => setDateFrom(e.target.value)} className="bg-slate-950 border border-slate-700 rounded-lg px-3 py-2 text-xs text-white outline-none focus:border-amber-500 transition-colors" />
                        <input type="date" value={dateTo} onChange={e => setDateTo(e.target.value)} className="bg-slate-950 border border-slate-700 rounded-lg px-3 py-2 text-xs text-white outline-none focus:border-amber-500 transition-colors" />
                    </div>
                    <button 
                        onClick={handleLoadMap} 
                        disabled={isLoading}
                        className="w-full h-12 bg-amber-600 hover:bg-amber-500 text-white font-black rounded-xl uppercase text-xs tracking-widest shadow-lg transition-all active:scale-95 flex items-center justify-center gap-2 border-2 border-amber-500 disabled:opacity-50"
                    >
                        {isLoading ? '⏳ ...' : '🔄 ' + t('map_load_btn')}
                    </button>
                </div>

                <div className="md:col-span-2 space-y-4 border-l border-slate-800 pl-6">
                    <h3 className="text-sm font-black text-slate-400 uppercase tracking-widest border-b border-slate-800 pb-2">{t('map_filter_workers')}</h3>
                    <div className="flex flex-wrap gap-2 max-h-24 overflow-y-auto custom-scrollbar">
                        {users.map(u => (
                            <button 
                                key={u.username}
                                onClick={() => toggleWorker(u.username)}
                                className={`px-3 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest border transition-all ${selectedWorkers.includes(u.username) ? 'bg-teal-500 border-teal-400 text-white shadow-[0_0_10px_rgba(20,184,166,0.3)]' : 'bg-slate-800 border-slate-700 text-slate-500 hover:text-slate-300'}`}
                            >
                                {u.nickname || u.username}
                            </button>
                        ))}
                    </div>
                </div>

                <div className="md:col-span-1 space-y-4 border-l border-slate-800 pl-6">
                    <h3 className="text-sm font-black text-slate-400 uppercase tracking-widest border-b border-slate-800 pb-2">Typy jázd</h3>
                    <div className="grid grid-cols-1 gap-y-2">
                        <div className="flex items-center gap-2 text-[10px] font-bold text-slate-500 uppercase">
                            <span className="w-4 h-1.5 bg-teal-500 rounded shadow-[0_0_5px_rgba(20,184,166,0.5)]"></span> {t('map_legend_full')} (VÝROBA)
                        </div>
                        <div className="flex items-center gap-2 text-[10px] font-bold text-slate-500 uppercase">
                            <span className="w-4 h-1.5 bg-sky-500 rounded shadow-[0_0_5px_rgba(14,165,233,0.5)]"></span> {t('map_legend_full')} (LOGISTIKA)
                        </div>
                        <div className="flex items-center gap-2 text-[10px] font-bold text-slate-500 uppercase">
                            <span className="w-4 h-0.5 bg-slate-600 border-b border-dashed"></span> {t('map_legend_empty')} (TRANZIT)
                        </div>
                    </div>
                </div>
            </div>
        </div>

        {/* MAP VISUALIZATION AREA */}
        <div className="bg-slate-900 border-2 border-slate-800 rounded-3xl shadow-2xl overflow-hidden relative min-h-[650px] flex flex-col group">
            {isLoading && (
                <div className="absolute inset-0 bg-slate-900/80 backdrop-blur-sm z-50 flex flex-col items-center justify-center gap-4">
                    <div className="w-16 h-16 border-4 border-amber-500 border-t-transparent rounded-full animate-spin"></div>
                    <p className="text-amber-500 font-black animate-pulse uppercase tracking-[0.4em] text-lg">{t('map_loading')}</p>
                </div>
            )}

            <div className="flex-grow relative overflow-hidden bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-slate-800/20 via-slate-900 to-slate-950">
                <svg 
                    viewBox={viewBox} 
                    className="w-full h-full min-h-[650px]" 
                    xmlns="http://www.w3.org/2000/svg"
                >
                    {/* Grid Background */}
                    <defs>
                        <pattern id="gridLarge" width="100" height="100" patternUnits="userSpaceOnUse">
                            <path d="M 100 0 L 0 0 0 100" fill="none" stroke="white" strokeWidth="1" strokeOpacity="0.05" />
                        </pattern>
                        <pattern id="gridSmall" width="20" height="20" patternUnits="userSpaceOnUse">
                            <path d="M 20 0 L 0 0 0 20" fill="none" stroke="white" strokeWidth="0.5" strokeOpacity="0.02" />
                        </pattern>

                        {/* Glow filters */}
                        <filter id="glow-teal">
                            <feGaussianBlur stdDeviation="2.5" result="coloredBlur"/>
                            <feMerge><feMergeNode in="coloredBlur"/><feMergeNode in="SourceGraphic"/></feMerge>
                        </filter>
                        <filter id="glow-sky">
                            <feGaussianBlur stdDeviation="2.5" result="coloredBlur"/>
                            <feMerge><feMergeNode in="coloredBlur"/><feMergeNode in="SourceGraphic"/></feMerge>
                        </filter>
                    </defs>

                    <rect width="10000" height="10000" x="-5000" y="-5000" fill="url(#gridSmall)" />
                    <rect width="10000" height="10000" x="-5000" y="-5000" fill="url(#gridLarge)" />

                    {/* ROUTES - Transit (Layer 1) - Manhattan Dashed */}
                    {segments.filter(s => s.isTransit).map((s, i) => (
                        <path 
                            key={`transit-${i}`}
                            d={getManhattanPath(s.from, s.to)}
                            fill="none"
                            stroke="#475569" 
                            strokeWidth="1.2" 
                            strokeDasharray="5 5" 
                            strokeOpacity="0.5"
                        />
                    ))}

                    {/* ROUTES - Work (Layer 2) - Manhattan Solid */}
                    {segments.filter(s => !s.isTransit).map((s, i) => (
                        <path 
                            key={`ride-${i}`}
                            d={getManhattanPath(s.from, s.to)}
                            fill="none"
                            stroke={s.taskType === 'prod' ? '#14b8a6' : '#0ea5e9'} 
                            strokeWidth="4" 
                            strokeLinecap="round" 
                            strokeLinejoin="round"
                            strokeOpacity="0.8"
                            filter={s.taskType === 'prod' ? 'url(#glow-teal)' : 'url(#glow-sky)'}
                            className="hover:stroke-white hover:strokeOpacity-100 transition-all cursor-pointer"
                        >
                            <title>{resolveName(s.worker)} | {s.from.label} → {s.to.label}</title>
                        </path>
                    ))}

                    {/* NODES - Workplaces & Sectors (Layer 3) */}
                    {nodes.map(node => {
                        const isSector = node.type === 'sector';
                        const colorValue = isSector ? (COLOR_MAP[node.color as keyof typeof COLOR_MAP]?.replace('bg-', '') || 'pink-500') : 'blue-500';

                        return (
                            <g key={node.id} transform={`translate(${node.x}, ${node.y})`} className="group/node">
                                {isSector ? (
                                    <rect 
                                        x="-12" y="-12" width="24" height="24" rx="6" 
                                        fill="currentColor" 
                                        className={`text-${colorValue} opacity-20 border-2 border-current shadow-lg group-hover/node:opacity-40 transition-opacity`}
                                    />
                                ) : (
                                    <circle 
                                        r="9" 
                                        fill="#0f172a" 
                                        stroke={node.type === 'wp' ? '#3b82f6' : '#0ea5e9'} 
                                        strokeWidth="2.5" 
                                        className="group-hover/node:stroke-white transition-colors"
                                    />
                                )}

                                {/* Label background for readability */}
                                <rect 
                                    x="-30" y={isSector ? -38 : -32} width="60" height="14" rx="4"
                                    fill="#000" fillOpacity="0.7"
                                    className="opacity-0 group-hover/node:opacity-100 transition-opacity pointer-events-none"
                                />
                                <text 
                                    y={isSector ? -28 : -22} 
                                    textAnchor="middle" 
                                    fill="white" 
                                    className="text-[9px] font-black uppercase tracking-widest opacity-0 group-hover/node:opacity-100 transition-opacity pointer-events-none drop-shadow-md"
                                >
                                    {node.label}
                                </text>
                            </g>
                        );
                    })}
                </svg>
            </div>

            {allData.length === 0 && !isLoading && (
                <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-700 pointer-events-none bg-slate-950/20">
                    <svg className="w-24 h-24 mb-6 opacity-10" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M9 20l-5.447-2.724A1 1 0 013 16.382V5.618a1 1 0 011.447-.894L9 7m0 13l6-3m-6 3V7m6 10l4.553 2.276A1 1 0 0021 18.382V7.618a1 1 0 00-.553-.894L15 4m0 13V4m0 0L9 7" />
                    </svg>
                    <p className="text-sm font-black uppercase tracking-[0.3em] opacity-30">Zvoľte filtre a stlačte "Generovať mapu"</p>
                    <p className="text-xs font-bold text-slate-800 uppercase tracking-widest mt-2 italic">Trasy budú vykreslené pomocou Manhattan geometrie (pravouhlé jazdy)</p>
                </div>
            )}
        </div>

        <div className="bg-slate-800/30 p-4 rounded-2xl border border-slate-700/50 flex items-center gap-4">
            <div className="w-10 h-10 rounded-full bg-amber-500/10 flex items-center justify-center text-amber-500 border border-amber-500/20">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                </svg>
            </div>
            <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest leading-relaxed">
                Manhattan Geometria: Mapa simuluje pohyb v uličkách skladu pomocou pravouhlých segmentov. 
                Súradnice sú relatívne k nastaveniu v sekcii Administrácia. Systém predpokladá najskôr horizontálny pohyb a následne vertikálny do cieľa.
            </p>
        </div>
    </div>
  );
};

export default MapVisualizationTab;

import React, { useState, useMemo } from 'react';
import { Task, UserData, MapSector, DBItem, SystemConfig } from '../../types/appTypes';
import { useLanguage } from '../LanguageContext';
import { COLOR_MAP } from '../../constants/uiConstants';

interface MapVisualizationTabProps {
  tasks: Task[];
  draftTasks: Task[];
  fetchSanons: () => Promise<any[]>;
  users: UserData[];
  mapSectors: MapSector[];
  workplaces: DBItem[];
  logisticsOperations: DBItem[];
  systemConfig: SystemConfig;
  resolveName: (username?: string | null) => string;
}

interface Point { x: number; y: number; label: string; type: 'wp' | 'sector' | 'log'; id: string; color?: string }
interface RouteSegment { from: Point; to: Point; worker: string; isTransit: boolean; taskType: 'prod' | 'log' }

const MapVisualizationTab: React.FC<MapVisualizationTabProps> = ({
  tasks, draftTasks, fetchSanons, users, mapSectors, workplaces, logisticsOperations, systemConfig, resolveName
}) => {
  const { t, language } = useLanguage();

  // Filtre
  const [dateFrom, setDateFrom] = useState(new Date().toISOString().split('T')[0]);
  const [dateTo, setDateTo] = useState(new Date().toISOString().split('T')[0]);
  const [selectedWorkers, setSelectedWorkers] = useState<string[]>([]);

  // Dáta
  const [allData, setAllData] = useState<Task[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  const handleLoadMap = async () => {
    setIsLoading(true);
    try {
        const sanons = await fetchSanons();
        const combined: Task[] = [...tasks, ...draftTasks];
        sanons.forEach(s => { if (s.tasks) combined.push(...s.tasks); });

        const startTs = new Date(dateFrom).setHours(0,0,0,0);
        const endTs = new Date(dateTo).setHours(23,59,59,999);

        const filtered = combined.filter(t => {
            const ts = t.completedAt || t.createdAt || 0;
            return ts >= startTs && ts <= endTs && t.isDone;
        });

        const uniqueMap = new Map();
        filtered.forEach(t => uniqueMap.set(t.id, t));
        setAllData(Array.from(uniqueMap.values()));
    } catch (e) {
        console.error(e);
    } finally {
        setIsLoading(false);
    }
  };

  // Trajektórie
  const { segments, nodes, viewBox } = useMemo(() => {
    const workerSegments: RouteSegment[] = [];
    const pointsMap = new Map<string, Point>();

    // 1. Zber bodov (Nodes)
    workplaces.forEach(w => pointsMap.set(`wp_${w.value}`, { x: w.coordX || 0, y: w.coordY || 0, label: w.value, type: 'wp', id: w.id }));
    logisticsOperations.forEach(l => pointsMap.set(`log_${l.value}`, { x: l.coordX || 0, y: l.coordY || 0, label: l.value, type: 'log', id: l.id }));
    mapSectors.forEach(s => pointsMap.set(`sector_${s.id}`, { x: s.coordX || 0, y: s.coordY || 0, label: s.name, type: 'sector', id: s.id, color: s.color }));

    // 2. Generovanie segmentov
    const filteredByWorker = selectedWorkers.length > 0 
        ? allData.filter(t => selectedWorkers.includes(t.completedBy || '')) 
        : allData;

    const grouped = new Map<string, Task[]>();
    filteredByWorker.forEach(t => {
        const worker = t.completedBy || 'Unknown';
        if (!grouped.has(worker)) grouped.set(worker, []);
        grouped.get(worker)!.push(t);
    });

    grouped.forEach((workerTasks, worker) => {
        const sorted = [...workerTasks].sort((a,b) => (a.completedAt || 0) - (b.completedAt || 0));
        let prevEndPoint: Point | null = null;

        sorted.forEach(task => {
            let startNode: Point | null = null;
            let endNode: Point | null = null;

            if (task.isLogistics) {
                const op = pointsMap.get(`log_${task.workplace}`);
                const src = pointsMap.get(`sector_${task.sourceSectorId}`);
                const trg = pointsMap.get(`sector_${task.targetSectorId}`);
                startNode = src || op || null;
                endNode = trg || op || null;
            } else {
                startNode = pointsMap.get(`sector_${task.pickedFromSectorId}`) || null;
                endNode = pointsMap.get(`wp_${task.workplace}`) || null;
            }

            if (startNode && endNode) {
                if (prevEndPoint) {
                    workerSegments.push({ from: prevEndPoint, to: startNode, worker, isTransit: true, taskType: task.isLogistics ? 'log' : 'prod' });
                }
                workerSegments.push({ from: startNode, to: endNode, worker, isTransit: false, taskType: task.isLogistics ? 'log' : 'prod' });
                prevEndPoint = endNode;
            }
        });
    });

    const allCoords = Array.from(pointsMap.values());
    if (allCoords.length === 0) return { segments: [], nodes: [], viewBox: "0 0 1000 1000" };

    // Dynamický padding založený na mierke
    const minX = Math.min(...allCoords.map(p => p.x)) - 100;
    const minY = Math.min(...allCoords.map(p => p.y)) - 100;
    const maxX = Math.max(...allCoords.map(p => p.x)) + 100;
    const maxY = Math.max(...allCoords.map(p => p.y)) + 100;

    return { 
        segments: workerSegments, 
        nodes: allCoords, 
        viewBox: `${minX} ${minY} ${maxX - minX} ${maxY - minY}` 
    };
  }, [allData, selectedWorkers, workplaces, logisticsOperations, mapSectors]);

  // Manhattan Path Helper
  const getManhattanPath = (from: Point, to: Point) => {
    return `M ${from.x} ${from.y} L ${to.x} ${from.y} L ${to.x} ${to.y}`;
  };

  const toggleWorker = (id: string) => {
      setSelectedWorkers(prev => prev.includes(id) ? prev.filter(w => w !== id) : [...prev, id]);
  };

  return (
    <div className="max-w-7xl mx-auto space-y-6 pb-20 animate-fade-in px-2 md:px-0">

        {/* CONTROL PANEL */}
        <div className="bg-slate-900 border border-slate-700 rounded-2xl p-5 shadow-xl">
            <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
                <div className="md:col-span-1 space-y-4">
                    <h3 className="text-sm font-black text-amber-500 uppercase tracking-widest border-b border-amber-900/30 pb-2">Analytické obdobie</h3>
                    <div className="grid grid-cols-2 gap-2">
                        <input type="date" value={dateFrom} onChange={e => setDateFrom(e.target.value)} className="bg-slate-950 border border-slate-700 rounded-lg px-3 py-2 text-xs text-white outline-none focus:border-amber-500 transition-colors" />
                        <input type="date" value={dateTo} onChange={e => setDateTo(e.target.value)} className="bg-slate-950 border border-slate-700 rounded-lg px-3 py-2 text-xs text-white outline-none focus:border-amber-500 transition-colors" />
                    </div>
                    <button 
                        onClick={handleLoadMap} 
                        disabled={isLoading}
                        className="w-full h-12 bg-amber-600 hover:bg-amber-500 text-white font-black rounded-xl uppercase text-xs tracking-widest shadow-lg transition-all active:scale-95 flex items-center justify-center gap-2 border-2 border-amber-500 disabled:opacity-50"
                    >
                        {isLoading ? '⏳ ...' : '🔄 ' + t('map_load_btn')}
                    </button>
                </div>

                <div className="md:col-span-2 space-y-4 border-l border-slate-800 pl-6">
                    <h3 className="text-sm font-black text-slate-400 uppercase tracking-widest border-b border-slate-800 pb-2">{t('map_filter_workers')}</h3>
                    <div className="flex flex-wrap gap-2 max-h-24 overflow-y-auto custom-scrollbar">
                        {users.map(u => (
                            <button 
                                key={u.username}
                                onClick={() => toggleWorker(u.username)}
                                className={`px-3 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest border transition-all ${selectedWorkers.includes(u.username) ? 'bg-teal-500 border-teal-400 text-white shadow-[0_0_10px_rgba(20,184,166,0.3)]' : 'bg-slate-800 border-slate-700 text-slate-500 hover:text-slate-300'}`}
                            >
                                {u.nickname || u.username}
                            </button>
                        ))}
                    </div>
                </div>

                <div className="md:col-span-1 space-y-4 border-l border-slate-800 pl-6">
                    <h3 className="text-sm font-black text-slate-400 uppercase tracking-widest border-b border-slate-800 pb-2">Metrika Mapy</h3>
                    <div className="bg-slate-950 p-3 rounded-xl border border-slate-800">
                        <div className="flex justify-between items-center mb-2">
                            <span className="text-[10px] font-black text-slate-500 uppercase">Mierka:</span>
                            <span className="text-[10px] font-black text-teal-400">10 PX = 1 M</span>
                        </div>
                        <div className="flex items-center gap-2">
                             <div className="h-1 w-[50px] bg-slate-700 rounded-full relative">
                                <div className="absolute inset-y-0 left-0 w-px bg-slate-500"></div>
                                <div className="absolute inset-y-0 right-0 w-px bg-slate-500"></div>
                             </div>
                             <span className="text-[9px] font-mono text-slate-500">5 metrov</span>
                        </div>
                    </div>
                </div>
            </div>
        </div>

        {/* MAP VISUALIZATION AREA */}
        <div className="bg-slate-900 border-2 border-slate-800 rounded-3xl shadow-2xl overflow-hidden relative min-h-[650px] flex flex-col group">
            {isLoading && (
                <div className="absolute inset-0 bg-slate-900/80 backdrop-blur-sm z-50 flex flex-col items-center justify-center gap-4">
                    <div className="w-16 h-16 border-4 border-amber-500 border-t-transparent rounded-full animate-spin"></div>
                    <p className="text-amber-500 font-black animate-pulse uppercase tracking-[0.4em] text-lg">{t('map_loading')}</p>
                </div>
            )}

            <div className="flex-grow relative overflow-hidden bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-slate-800/20 via-slate-900 to-slate-950">
                <svg 
                    viewBox={viewBox} 
                    className="w-full h-full min-h-[650px]" 
                    xmlns="http://www.w3.org/2000/svg"
                >
                    {/* Grid Background - Adjusted for 10px=1m scale */}
                    <defs>
                        {/* Mriežka každých 5 metrov (50px) */}
                        <pattern id="grid5m" width="50" height="50" patternUnits="userSpaceOnUse">
                            <path d="M 50 0 L 0 0 0 50" fill="none" stroke="white" strokeWidth="1" strokeOpacity="0.05" />
                        </pattern>
                        {/* Jemná mriežka každý 1 meter (10px) */}
                        <pattern id="grid1m" width="10" height="10" patternUnits="userSpaceOnUse">
                            <path d="M 10 0 L 0 0 0 10" fill="none" stroke="white" strokeWidth="0.5" strokeOpacity="0.02" />
                        </pattern>

                        <filter id="glow-teal">
                            <feGaussianBlur stdDeviation="2.5" result="coloredBlur"/>
                            <feMerge><feMergeNode in="coloredBlur"/><feMergeNode in="SourceGraphic"/></feMerge>
                        </filter>
                        <filter id="glow-sky">
                            <feGaussianBlur stdDeviation="2.5" result="coloredBlur"/>
                            <feMerge><feMergeNode in="coloredBlur"/><feMergeNode in="SourceGraphic"/></feMerge>
                        </filter>
                    </defs>

                    <rect width="10000" height="10000" x="-5000" y="-5000" fill="url(#grid1m)" />
                    <rect width="10000" height="10000" x="-5000" y="-5000" fill="url(#grid5m)" />

                    {/* ROUTES - Transit (Layer 1) - Manhattan Dashed */}
                    {segments.filter(s => s.isTransit).map((s, i) => (
                        <path 
                            key={`transit-${i}`}
                            d={getManhattanPath(s.from, s.to)}
                            fill="none"
                            stroke="#475569" 
                            strokeWidth="1.2" 
                            strokeDasharray="5 5" 
                            strokeOpacity="0.5"
                        />
                    ))}

                    {/* ROUTES - Work (Layer 2) - Manhattan Solid */}
                    {segments.filter(s => !s.isTransit).map((s, i) => (
                        <path 
                            key={`ride-${i}`}
                            d={getManhattanPath(s.from, s.to)}
                            fill="none"
                            stroke={s.taskType === 'prod' ? '#14b8a6' : '#0ea5e9'} 
                            strokeWidth="4" 
                            strokeLinecap="round" 
                            strokeLinejoin="round"
                            strokeOpacity="0.8"
                            filter={s.taskType === 'prod' ? 'url(#glow-teal)' : 'url(#glow-sky)'}
                            className="hover:stroke-white hover:strokeOpacity-100 transition-all cursor-pointer"
                        >
                            <title>{resolveName(s.worker)} | {s.from.label} → {s.to.label}</title>
                        </path>
                    ))}

                    {/* NODES - Workplaces & Sectors (Layer 3) */}
                    {nodes.map(node => {
                        const isSector = node.type === 'sector';
                        const colorValue = isSector ? (COLOR_MAP[node.color as keyof typeof COLOR_MAP]?.replace('bg-', '') || 'pink-500') : 'blue-500';

                        return (
                            <g key={node.id} transform={`translate(${node.x}, ${node.y})`} className="group/node">
                                {isSector ? (
                                    <rect 
                                        x="-12" y="-12" width="24" height="24" rx="6" 
                                        fill="currentColor" 
                                        className={`text-${colorValue} opacity-20 border-2 border-current shadow-lg group-hover/node:opacity-40 transition-opacity`}
                                    />
                                ) : (
                                    <circle 
                                        r="9" 
                                        fill="#0f172a" 
                                        stroke={node.type === 'wp' ? '#3b82f6' : '#0ea5e9'} 
                                        strokeWidth="2.5" 
                                        className="group-hover/node:stroke-white transition-colors"
                                    />
                                )}

                                <rect 
                                    x="-30" y={isSector ? -38 : -32} width="60" height="14" rx="4"
                                    fill="#000" fillOpacity="0.7"
                                    className="opacity-0 group-hover/node:opacity-100 transition-opacity pointer-events-none"
                                />
                                <text 
                                    y={isSector ? -28 : -22} 
                                    textAnchor="middle" 
                                    fill="white" 
                                    className="text-[9px] font-black uppercase tracking-widest opacity-0 group-hover/node:opacity-100 transition-opacity pointer-events-none drop-shadow-md"
                                >
                                    {node.label}
                                </text>
                            </g>
                        );
                    })}
                </svg>

                {/* VIZUÁLNY SCALE OVERLAY (FIXNÝ V ROHU) */}
                <div className="absolute bottom-6 right-6 bg-slate-900/60 backdrop-blur-md border border-slate-700 p-3 rounded-xl pointer-events-none shadow-2xl">
                     <div className="flex flex-col items-center gap-2">
                        <div className="flex items-center gap-0 w-[100px] h-3 border-x border-slate-400 relative">
                            <div className="absolute top-1/2 left-0 right-0 h-px bg-slate-400 -translate-y-1/2"></div>
                            <div className="absolute top-0 left-1/2 w-px h-full bg-slate-600/50"></div>
                        </div>
                        <span className="text-[10px] font-black text-white uppercase tracking-widest">10 METROV</span>
                        <span className="text-[8px] font-bold text-slate-500">(10px = 1m)</span>
                     </div>
                </div>
            </div>

            {allData.length === 0 && !isLoading && (
                <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-700 pointer-events-none bg-slate-950/20">
                    <svg className="w-24 h-24 mb-6 opacity-10" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M9 20l-5.447-2.724A1 1 0 013 16.382V5.618a1 1 0 011.447-.894L9 7m0 13l6-3m-6 3V7m6 10l4.553 2.276A1 1 0 0021 18.382V7.618a1 1 0 00-.553-.894L15 4m0 13V4m0 0L9 7" />
                    </svg>
                    <p className="text-sm font-black uppercase tracking-[0.3em] opacity-30">Zvoľte filtre a stlačte "Generovať mapu"</p>
                </div>
            )}
        </div>

        <div className="bg-slate-800/30 p-4 rounded-2xl border border-slate-700/50 flex items-center gap-4">
            <div className="w-10 h-10 rounded-full bg-amber-500/10 flex items-center justify-center text-amber-500 border border-amber-500/20">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                </svg>
            </div>
            <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest leading-relaxed">
                Manhattan Geometria & Mierka: Mapa simuluje pohyb pomocou pravouhlých segmentov. 
                Všetky súradnice v systéme sú v mierke 10 pixelov na 1 reálny meter. 
                Grid na pozadí má hlavné štvorce o veľkosti 5x5 metrov.
            </p>
        </div>
    </div>
  );
};

export default MapVisualizationTab;
